class MiddlewarePipeline {
  private middleware: Function[] = [];
  private result: any = null;

  public addMiddleware(middleware: Function) {
    this.middleware.push(middleware);
  }

  public run(data: any) {
    let promise = Promise.resolve(data);
    for (const middleware of this.middleware) {
      promise = promise.then(result => {
        return new Promise(resolve => {
          middleware(result, (err, result) => {
            if (err) {
              resolve({ error: err });
            } else {
              resolve(result);
            }
          });
        });
      });
    }
    return promise;
  }
}

class SynchronousMiddleware {
  public exec(data: any) {
    return data.toUpperCase();
  }
}

class AsynchronousMiddleware {
  public exec(data: any) {
    return new Promise((resolve, reject) => {
      setTimeout(() => {
        resolve(data.toUpperCase());
      }, 1000);
    });
  }
}

const pipeline = new MiddlewarePipeline();
const synchronousMiddleware = new SynchronousMiddleware();
const asynchronousMiddleware = new AsynchronousMiddleware();

pipeline.addMiddleware(synchronousMiddleware.exec);
pipeline.addMiddleware(asynchronousMiddleware.exec);

const result = pipeline.run('hello').then(data => data);
result.then((data) => console.log(data)).catch((error) => console.error(error));

